css:
body {
  background-color: #140E08 !important;
}
.header {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #302016 var(--ts-opacity-header), transparent) 0%,
    color-mix(in srgb, #241910 var(--ts-opacity-header), transparent) 100%
  ) !important;
  border-bottom: 2px solid color-mix(in srgb, #D4943C var(--ts-opacity-header), transparent) !important;
}
.sidebar {
  background: linear-gradient(180deg, #241910 0%, #1E1510 50%, #1A120B 100%) !important;
  border-right: 1px solid #443020 !important;
}
.album-row {
  background: color-mix(in srgb, #241910 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
  border: 1.5px solid color-mix(in srgb, #443020 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
}
.album-row:hover {
  background: color-mix(in srgb, #3C2A1C var(--ts-opacity-row), transparent) !important;
  border-color: color-mix(in srgb, #D4943C var(--ts-opacity-row), transparent) !important;
}
.album-card {
  background: color-mix(in srgb, #241910 var(--ts-opacity-card), transparent) !important;
  border: 1.5px solid color-mix(in srgb, #443020 var(--ts-opacity-card), transparent) !important;
  border-radius: 12px !important;
}
.album-card:hover {
  border-color: color-mix(in srgb, #D4943C var(--ts-opacity-card), transparent) !important;
}
.card-info {
  background: color-mix(in srgb, #1E1510 var(--ts-opacity-card), transparent) !important;
}
.modal {
  background: linear-gradient(180deg, #2A1C12 0%, #241910 100%) !important;
  border: 2px solid #5A3C22 !important;
  border-radius: 14px !important;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
}
button {
  background: linear-gradient(180deg, #3C2A1C 0%, #302016 100%) !important;
  border: 1.5px solid #5A3C22 !important;
  color: #F0E4D4 !important;
}
button:hover {
  background: linear-gradient(180deg, #4A3424 0%, #3C2A1C 100%) !important;
  border-color: #D4943C !important;
}
a, .artist-link { color: #D4943C !important; }
a:hover, .artist-link:hover { color: #E8AE58 !important; }
input, select, textarea {
  background: #1A120B !important;
  border: 1.5px solid #443020 !important;
  color: #F0E4D4 !important;
}
input:focus, select:focus, textarea:focus {
  border-color: #D4943C !important;
  box-shadow: 0 0 0 3px rgba(212, 148, 60, 0.12);
}
::selection { background: #5A3C22; color: #F0E4D4; }
